import { Component, computed, OnDestroy } from '@angular/core';
import { LoaderService } from '../../../shared/loader/loader.service';
import { MatTableDataSource } from '@angular/material/table';
import { MatDialog, MatDialogConfig } from '@angular/material/dialog';
import { MaPort } from './port.model';
import { PortService } from './port.service';
import { SnackbarService } from '../../../shared/snack-bar/snack-bar.service';
import { CommonModule } from '@angular/common';
import { MatIcon } from '@angular/material/icon';
import { FormsModule } from '@angular/forms';
import { MatFormField } from '@angular/material/form-field';
import { MatLabel } from '@angular/material/form-field';
import { MatTableModule } from '@angular/material/table';
import { MatInputModule } from '@angular/material/input';
import { ViewFieldsComponent } from '../../../components/create-port/view-fields/view-fields.component';
import { CreatePortTariffComponent } from '../../../components/create-port-tariff/create-port-tariff.component';
import { MatTooltipModule } from '@angular/material/tooltip';
import { Subject } from 'rxjs';
import { debounceTime } from 'rxjs/operators';

@Component({
  selector: 'app-port',
  standalone: true,
  imports: [
    CommonModule,
    MatIcon,
    FormsModule,
    MatFormField,
    MatLabel,
    MatTableModule,
    MatInputModule,
    MatTooltipModule
  ],
  templateUrl: './port.component.html',
  styleUrl: './port.component.css'
})
export class PortComponent implements OnDestroy {
  constructor(
    private loaderService: LoaderService,
    private portService: PortService,
    private snackBar: SnackbarService,
    private dialog: MatDialog,
  ) { }

  isLoading = computed(() => this.loaderService.loading());
  searchTerm: string = '';
  displayedColumns = ['Sl.No', 'country', 'name', 'Action'];
  dataSource = new MatTableDataSource<any>();
  currentPage = 1;
  pageSize = 50;
  allDataLoaded = false;
  totalCount = 0;
  private searchSubject = new Subject<string>();

  ngOnInit() {
    this.getMaPortTariffRules(true);
    // Setup debounce for search
    this.searchSubject
      .pipe(
        debounceTime(1000)
      )
      .subscribe(() => {
        this.onSearch();
      });
  }

  ngOnDestroy() {
    this.searchSubject.complete();
  }

  inputSearch(): void {
    if (this.searchTerm.trim() === '') {
      this.onSearch();
    } else {
      this.searchSubject.next(this.searchTerm);
    }
  }

  //method to filter the records in db
  onSearch(): void {
    this.getMaPortTariffRules(true);
  }

  // method to clear the searchterm
  clearSearch() {
    this.searchTerm = '';
    this.getMaPortTariffRules(true);
  }

  // method to fetch the tariff rules from db
  getMaPortDataFromDb(reset = false) {
    if (reset) {
      this.currentPage = 1;
      this.allDataLoaded = false;
      this.dataSource.data = [];
      this.totalCount = 0;
    }

    const body = {
      page: this.currentPage,
      page_size: this.pageSize,
      query: this.searchTerm.trim(),
    };

    this.loaderService.show();

    this.portService.portDataFromDb(body).subscribe({
      next: (response: { data: MaPort[]; total_count: number }) => {
        const newData = response.data;
        this.totalCount = response.total_count;

        this.dataSource.data = [...this.dataSource.data, ...newData];
        if (this.dataSource.data.length >= this.totalCount) {
          this.allDataLoaded = true;
        }

        this.currentPage++;
        this.loaderService.hide();
      },
      error: (err) => {
        console.error('Error fetching tariff rules:', err);
        this.snackBar.showError('Something went wrong. Please try again later.');
        this.loaderService.hide();
      }
    });
  }


  getMaPortTariffRules(reset = false) {
    if (reset) {
      this.currentPage = 1;
      this.allDataLoaded = false;
      this.dataSource.data = [];
      this.totalCount = 0;
    }
    const body = {
      page: this.currentPage,
      page_size: this.pageSize,
      query_name: this.searchTerm.trim(),
    };

    this.loaderService.show();

    this.portService.getTariffRules(body).subscribe({
      next: (response: any) => {
        const newData = response.data;
        this.totalCount = response.total;
        this.dataSource.data = [...this.dataSource.data, ...newData];

        if (this.dataSource.data.length >= this.totalCount) {
          this.allDataLoaded = true;
        }

        this.currentPage++;
        this.loaderService.hide();
      },
      error: (err) => {
        console.error('Error fetching tariff rules:', err);
        this.snackBar.showError('Something went wrong. Please try again later.');
        this.loaderService.hide();
      }
    });
  }
  //calling the portlist api on scroll 
  onManualScroll(): void {
    const scrollContainer = document.querySelector('.table-container');

    if (scrollContainer) {
      const scrollPosition = scrollContainer.scrollTop + scrollContainer.clientHeight;
      const scrollHeight = scrollContainer.scrollHeight;

      if (
        scrollPosition >= scrollHeight - 10 &&
        !this.loaderService.loading() &&
        !this.allDataLoaded
      ) {
        this.getMaPortTariffRules();
      }
    }
  }

  // method to open AddPortDialog
  openAddPortDialog() {
    const dialogConfig = new MatDialogConfig();
    dialogConfig.position = { right: '0' };
    dialogConfig.height = '100%';
    dialogConfig.width = '96vw';
    dialogConfig.maxWidth = '100vw';
    dialogConfig.disableClose = true;
    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];

    const dialogRef = this.dialog.open(CreatePortTariffComponent, dialogConfig);
    dialogRef.afterClosed().subscribe(result => {
      if (result === 'refresh') {
        // this.getMaPortDataFromDb(true);
        this.getMaPortTariffRules(true);
      } else if (result && result.data) {
        // Handle the returned tariff data

        // Here you can process the data as needed
        // For example, you might want to save it to a local storage or state management
        // Or you might want to make an API call to save it

        // For now, just show a success message
        this.snackBar.showSuccess('Tariffs saved successfully');
      }
    });
  }

  // method to open EditPortDialog
  openEditPortDialog(rowData: MaPort) {
    const dialogConfig = new MatDialogConfig();
    dialogConfig.position = { right: '0' };
    dialogConfig.height = '100%';
    dialogConfig.width = '96vw';
    dialogConfig.maxWidth = '100vw';
    dialogConfig.disableClose = true;
    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
    dialogConfig.data = { rowData };


    const dialogRef = this.dialog.open(CreatePortTariffComponent, dialogConfig);
    dialogRef.afterClosed().subscribe(result => {
      if (result === 'refresh') {
        // this.getMaPortDataFromDb(true);
        this.getMaPortTariffRules(true);
      } else if (result && result.data) {
        // Handle the returned tariff data


        // Here you can process the data as needed
        // For example, you might want to save it to a local storage or state management
        // Or you might want to make an API call to save it

        // For now, just show a success message
        this.snackBar.showSuccess('Tariffs updated successfully');
      }
    });
  }

  // method to open dialog to add the additional vessel fields
  openViewFieldsDialog(vessel_fields: any) {
    const data = {
      vessel_fields: vessel_fields.vessel_fields,
    }
    this.dialog.open(ViewFieldsComponent, {
      data: data,
      width: '450px',
      disableClose: true,
    });
  }
}
